{
  "results": [
    {
      "server": "aicx-mcp",
      "tools": [
        {
          "tool_name": "aicx-mcp__aicx_search",
          "description": "Semantic search over the canonical corpus. Fails fast with kind/reason/recommendation when the index or embedder is not ready. Filter pushdown (agent/score/date/hours) iterates a bounded retrieval pool (up to 10x the requested limit) so a corpus whose top-N raw hits all sit outside the filter window still surfaces inside-window matches further down the ranking instead of returning silent-empty. When the cap is examined without satisfying the limit, the response carries a `filter_pushdown` payload with `kind=\"filter_yielded_partial\"` so callers can distinguish bounded under-delivery from a genuinely empty corpus.",
          "score": 1.0,
          "input_schema": {
            "$defs": {
              "FrameKind": {
                "description": "Canonical stream/frame classification for a timeline entry or stored chunk.\n\nThis axis is intentionally orthogonal to `role`: source formats drift in how\nthey spell assistant reasoning or tool payloads, but downstream retrieval\nneeds one stable vocabulary for \"which channel is this?\".",
                "enum": [
                  "user_msg",
                  "agent_reply",
                  "internal_thought",
                  "tool_call",
                  "system_note"
                ],
                "type": "string"
              }
            },
            "$schema": "https://json-schema.org/draft/2020-12/schema",
            "properties": {
              "agent": {
                "description": "Optional agent filter",
                "type": [
                  "string",
                  "null"
                ]
              },
              "date": {
                "description": "Optional date filter (single day or range)",
                "type": [
                  "string",
                  "null"
                ]
              },
              "frame_kind": {
                "anyOf": [
                  {
                    "$ref": "#/$defs/FrameKind"
                  },
                  {
                    "type": "null"
                  }
                ],
                "description": "Optional frame/channel filter: user_msg, agent_reply, internal_thought, tool_call"
              },
              "hours": {
                "description": "Hours to look back (0 = all time)",
                "format": "uint64",
                "minimum": 0,
                "type": [
                  "integer",
                  "null"
                ]
              },
              "kind": {
                "description": "Optional canonical corpus kind filter: conversations, plans, reports, other",
                "type": [
                  "string",
                  "null"
                ]
              },
              "limit": {
                "default": 20,
                "description": "Max results to return (default: 10)",
                "format": "uint",
                "minimum": 0,
                "type": "integer"
              },
              "project": {
                "description": "Optional project filter (case-insensitive substring). Prefer\n`projects` for cross-project search.",
                "type": [
                  "string",
                  "null"
                ]
              },
              "projects": {
                "description": "Optional project filters for cross-project search.",
                "items": {
                  "type": "string"
                },
                "type": [
                  "array",
                  "null"
                ]
              },
              "query": {
                "description": "Search query text",
                "type": "string"
              },
              "score": {
                "description": "Minimum score threshold (0-100)",
                "format": "uint8",
                "maximum": 255,
                "minimum": 0,
                "type": [
                  "integer",
                  "null"
                ]
              },
              "since": {
                "description": "Optional lower date bound or single-day shorthand",
                "type": [
                  "string",
                  "null"
                ]
              },
              "slim": {
                "default": true,
                "description": "Return only metadata without full snippet content",
                "type": "boolean"
              },
              "sort": {
                "description": "Optional sort order: newest, oldest, score",
                "type": [
                  "string",
                  "null"
                ]
              },
              "until": {
                "description": "Optional upper date bound",
                "type": [
                  "string",
                  "null"
                ]
              },
              "verbose": {
                "default": false,
                "description": "Return snippet + full evidence",
                "type": "boolean"
              }
            },
            "required": [
              "query"
            ],
            "title": "SearchParams",
            "type": "object"
          }
        }
      ]
    }
  ],
  "total_hidden_tools": 140,
  "status": "ready",
  "note": null
}

