                ]
              },
              "since": {
                "description": "Optional lower date bound (YYYY-MM-DD or single-day shorthand like 2026-04-23..)",
                "type": [
                  "string",
                  "null"
                ]
              },
              "slim": {
                "default": true,
                "description": "Return only metadata without full snippet content",
                "type": "boolean"
              },
              "sort": {
                "description": "Sort order: newest (default), oldest",
                "type": [
                  "string",
                  "null"
                ]
              },
              "strict": {
                "default": false,
                "description": "Strict mode: only emit high-confidence intents (default: false)",
                "type": "boolean"
              },
              "unresolved": {
                "default": false,
                "description": "Filter to intent entries lacking a matching outcome in the same session",
                "type": "boolean"
              },
              "unresolved_mode": {
                "anyOf": [
                  {
                    "$ref": "#/$defs/UnresolvedMode"
                  },
                  {
                    "type": "null"
                  }
                ],
                "default": null,
                "description": "Mode for filtering unresolved entries: session (default) or intent"
              },
              "until": {
                "description": "Optional upper date bound (YYYY-MM-DD)",
                "type": [
                  "string",
                  "null"
                ]
              },
              "verbose": {
                "default": false,
                "description": "Return snippet + full evidence",
                "type": "boolean"
              }
            },
            "title": "IntentsParams",
            "type": "object"
          }
        }
      ]
    }
  ],
  "total_hidden_tools": 140,
  "status": "ready",
  "note": null
}

